import{_ as t,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as i,o as s,c as d,a2 as l}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"User Rate Limits","description":"","frontmatter":{},"headers":[],"relativePath":"my/Safety/user-rate-limits.md","filePath":"my/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),r={name:"my/Safety/user-rate-limits.md"};function o(p,e,n,u,c,m){return s(),d("div",null,[...e[0]||(e[0]=[l('<h1 id="user-rate-limits" tabindex="-1">User Rate Limits <a class="header-anchor" href="#user-rate-limits" aria-label="Permalink to &quot;User Rate Limits&quot;">​</a></h1><p>User rate limits က regular users သို့မဟုတ် visitors တွေ homepage မှ files upload လုပ်နိုင်တဲ့ frequency ကိုထိန်းချုပ်ပါတယ်။ public upload pages ကို abuse မဖြစ်စေဖို့ကူညီပါတယ်။</p><p>ဒီ feature က homepage uploads ကိုသာသက်ရောက်ပါတယ်။ Admin uploads နဲ့ API Tokens ဖြင့်လုပ်တဲ့ uploads တွေကို user rate limits မကန့်သတ်ပါ။</p><h2 id="ဘယ်နေရာမှာ-configure-လုပ်မလဲ" tabindex="-1">ဘယ်နေရာမှာ Configure လုပ်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-configure-လုပ်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ Configure လုပ်မလဲ&quot;">​</a></h2><p>admin panel ကိုဖွင့်ပြီး သွားပါ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+t+'" alt="User rate limit settings" loading="lazy"></p><h2 id="rate-limits-enable-လုပ်ခြင်း" tabindex="-1">Rate Limits Enable လုပ်ခြင်း <a class="header-anchor" href="#rate-limits-enable-လုပ်ခြင်း" aria-label="Permalink to &quot;Rate Limits Enable လုပ်ခြင်း&quot;">​</a></h2><p><code>Enable Rate Limits</code> ကို on လုပ်ပြီးနောက် ImgBed က uploader IP address အလိုက် recent uploads ကို track လုပ်ပါတယ်။</p><p>Default values:</p><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Detection window</td><td>1.5 hours</td><td>upload records ကို ဘယ်လောက်နောက်ပြန်တွက်မလဲ။</td></tr><tr><td>Max file count</td><td>20</td><td>detection window ထဲမှာခွင့်ပြုတဲ့ files အများဆုံးအရေအတွက်။</td></tr><tr><td>Single file size limit</td><td>20 MB</td><td>file တစ်ခုရဲ့ maximum size။</td></tr><tr><td>Total upload size limit</td><td>200 MB</td><td>detection window ထဲက maximum total upload size။</td></tr></tbody></table><p>ဥပမာ 1.5 hour window, 20 files, file တစ်ခု 20 MB, total 200 MB ဆိုလျှင် same IP မှ uploads တွေက configured limit တစ်ခုခုကျော်တာနဲ့ blocked ဖြစ်ပါမယ်။</p><h2 id="file-types-exclude-လုပ်ခြင်း" tabindex="-1">File Types Exclude လုပ်ခြင်း <a class="header-anchor" href="#file-types-exclude-လုပ်ခြင်း" aria-label="Permalink to &quot;File Types Exclude လုပ်ခြင်း&quot;">​</a></h2><p><code>Excluded upload file types</code> က regular users သို့မဟုတ် visitors တွေ selected file categories upload လုပ်တာကိုတားပါတယ်။</p><p>Available categories:</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif နဲ့ image files ဆင်တူများ</td></tr><tr><td>Videos</td><td>mp4, webm, mov နဲ့ video files ဆင်တူများ</td></tr><tr><td>Audio</td><td>mp3, flac, wav နဲ့ audio files ဆင်တူများ</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx နဲ့ document files ဆင်တူများ</td></tr><tr><td>Other</td><td>အထက်ပါ categories ထဲမပါတဲ့ files၊ ဥပမာ zip, rar, exe, apk</td></tr></tbody></table><p>default အနေနဲ့ type မရွေးထားပါ၊ ဆိုလိုတာက allowed ဖြစ်ပါတယ်။</p><p>type တစ်ခုကို click လုပ်ရင် highlighted ဖြစ်ပြီး အဲဒီ type က blocked ဖြစ်ပါတယ်။</p><p><code>Other</code> ရွေးထားလျှင် zip သို့မဟုတ် rar files upload လုပ်တဲ့ visitors တွေ blocked ဖြစ်ပြီး ဒီ file type မထောက်ပံ့ဘူးဆိုတဲ့ message မြင်ရပါမယ်။</p><h2 id="block-messages" tabindex="-1">Block Messages <a class="header-anchor" href="#block-messages" aria-label="Permalink to &quot;Block Messages&quot;">​</a></h2><p>limit trigger ဖြစ်တဲ့အခါ users တွေက သက်ဆိုင်တဲ့ message မြင်ရပါမယ်:</p><p><img src="'+a+'" alt="Too frequent upload message" loading="lazy"></p><table tabindex="0"><thead><tr><th>Scenario</th><th>Message Meaning</th></tr></thead><tbody><tr><td>Single file too large</td><td>file ကကြီးလွန်းပြီး upload မလုပ်ခင် compress လုပ်သင့်သည်။</td></tr><tr><td>File type blocked</td><td>ဒီ file type ကို support မလုပ်ပါ။ ဖယ်ရှားပြီးထပ်ကြိုးစားပါ။</td></tr><tr><td>Uploads too frequent</td><td>recent uploads တွေ frequency မြင့်လွန်းပြီး retry time ပြသည်။</td></tr><tr><td>Total size too high</td><td>recent total upload size မြင့်လွန်းပြီး retry time ပြသည်။</td></tr></tbody></table><h2 id="ဘယ်အချိန်မှာ-enable-လုပ်သင့်လဲ" tabindex="-1">ဘယ်အချိန်မှာ Enable လုပ်သင့်လဲ <a class="header-anchor" href="#ဘယ်အချိန်မှာ-enable-လုပ်သင့်လဲ" aria-label="Permalink to &quot;ဘယ်အချိန်မှာ Enable လုပ်သင့်လဲ&quot;">​</a></h2><p>သင့် upload homepage က public accessible ဖြစ်လျှင် user rate limits enable လုပ်ပါ။</p><p>အသုံးများတဲ့အကြောင်းရင်းများ:</p><ul><li>scripted bulk uploads ကိုစိတ်ပူလျှင်။</li><li>visitor uploads ကြီးကြီးမားမားတွေကို limit လုပ်ချင်လျှင်။</li><li>regular users တွေကို images ပဲ upload လုပ်စေချင်ပြီး archives သို့မဟုတ် installers မလိုချင်လျှင်။</li><li>public upload ကိုဖွင့်ထားချင်ပေမယ့် resource usage ကိုထိန်းချင်လျှင်။</li></ul><p>site က သင့်တစ်ယောက်တည်းအတွက်ဖြစ်လျှင်၊ သို့မဟုတ် administrators တွေသာ upload လုပ်လျှင် ဒီ setting ကို disabled ထားနိုင်ပါတယ်။</p>',28)])])}const f=i(r,[["render",o]]);export{b as __pageData,f as default};
